import React, { useState } from "react";

function CompareModels() {
  const [results, setResults] = useState(null);

  const runCompare = async () => {
    const res = await fetch("http://127.0.0.1:5000/compare", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({})
    });

    const data = await res.json();
    if (data.status === "success") {
      setResults(data.results);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>📊 Model Comparison</h2>

      <button onClick={runCompare}>Run Comparison</button>

      {results && (
        <table border="1" cellPadding="10" style={{ marginTop: "20px" }}>
          <thead>
            <tr>
              <th>Metric</th>
              <th>Isolation Forest</th>
              <th>One-Class SVM</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>TPR</td>
              <td>{results.IsolationForest.TPR}%</td>
              <td>{results.OneClassSVM.TPR}%</td>
            </tr>
            <tr>
              <td>FNR</td>
              <td>{results.IsolationForest.FNR}%</td>
              <td>{results.OneClassSVM.FNR}%</td>
            </tr>
            <tr>
              <td>FPR</td>
              <td>{results.IsolationForest.FPR}%</td>
              <td>{results.OneClassSVM.FPR}%</td>
            </tr>
            <tr>
              <td>TNR</td>
              <td>{results.IsolationForest.TNR}%</td>
              <td>{results.OneClassSVM.TNR}%</td>
            </tr>
            <tr>
              <td>Precision</td>
              <td>{results.IsolationForest.Precision}%</td>
              <td>{results.OneClassSVM.Precision}%</td>
            </tr>
            <tr>
              <td>F1 Score</td>
              <td>{results.IsolationForest.F1}%</td>
              <td>{results.OneClassSVM.F1}%</td>
            </tr>
          </tbody>
        </table>
      )}
    </div>
  );
}

export default CompareModels;
